arguments.code:
import json

# We need to find the latest release version for each package name
packages = env['data_7']
latest_versions = {}

for p in packages:
    name = p['Name']
    version = p['Version']
    try:
        v_info = json.loads(p['VersionInfo']) if isinstance(p['VersionInfo'], str) else p['VersionInfo']
        if v_info.get('IsRelease'):
            ordinal = v_info.get('Ordinal', 0)
            if name not in latest_versions or ordinal > latest_versions[name]['ordinal']:
                latest_versions[name] = {'version': version, 'ordinal': ordinal}
    except Exception as e:
        pass

print("Latest versions:")
for name, info in latest_versions.items():
    print(f"{name}: {info['version']}")

env['latest_versions'] = latest_versions

